exec('import atexit, html, secrets, socket, sys, threading, time, traceback, urllib.request\nfrom pathlib import Path\nimport uvicorn, webview\nfrom icloudpd_web.app import create_app\nfrom icloudpd_web.auth import Authenticator\nAPP_TITLE = "iCloudPD Web"\nHOST = "127.0.0.1"\nDATA_DIR = Path.home() / ".icloudpd-web-desktop"\nHELPER_NAME = "icloudpd-helper"\n\ndef pick_port():\n    sock = socket.socket(socket.AF_INET, socket.SOCK_STREAM)\n    sock.bind((HOST, 0))\n    port = sock.getsockname()[1]\n    sock.close()\n    return port\n\ndef helper_candidates():\n    if getattr(sys, "frozen", False):\n        paths = [Path(sys.executable).resolve().parent / HELPER_NAME]\n        meipass = getattr(sys, "_MEIPASS", None)\n        if meipass:\n            paths.append(Path(meipass) / HELPER_NAME)\n            paths.append(Path(meipass) / "helpers" / HELPER_NAME)\n        return paths\n    return [Path(__file__).resolve().with_name("icloudpd_runner.py")]\n\ndef resolve_helper():\n    for candidate in helper_candidates():\n        if candidate.exists():\n            return candidate\n    raise FileNotFoundError("icloudpd helper executable is missing")\n\nclass Backend:\n    def __init__(self):\n        self.port = pick_port()\n        self.url = f"http://{HOST}:{self.port}"\n        self.helper = resolve_helper()\n        self.server = uvicorn.Server(uvicorn.Config(create_app(data_dir=DATA_DIR, authenticator=Authenticator(password_hash=None), session_secret=secrets.token_urlsafe(32), icloudpd_argv=self.icloudpd_argv), host=HOST, port=self.port, log_level="info", access_log=False))\n        self.thread = threading.Thread(target=self.server.run, daemon=True)\n        self.stopped = False\n\n    def icloudpd_argv(self, tail):\n        if self.helper.suffix == ".py":\n            return [sys.executable, str(self.helper), *tail]\n        return [str(self.helper), *tail]\n\n    def start(self):\n        DATA_DIR.mkdir(parents=True, exist_ok=True)\n        self.thread.start()\n        deadline = time.time() + 20\n        while time.time() < deadline:\n            try:\n                with urllib.request.urlopen(f"{self.url}/auth/status", timeout=1) as resp:\n                    if resp.status == 200:\n                        return\n            except Exception:\n                time.sleep(0.2)\n        raise RuntimeError("Timed out while waiting for the local web server")\n\n    def stop(self):\n        if self.stopped:\n            return\n        self.stopped = True\n        self.server.should_exit = True\n        self.thread.join(timeout=5)\n\ndef error_html(exc):\n    details = html.escape("".join(traceback.format_exception_only(type(exc), exc)).strip())\n    return f"<!doctype html><html><body style=\"font-family: -apple-system, BlinkMacSystemFont, sans-serif; padding: 32px; line-height: 1.5;\"><h2 style=\"margin-top: 0;\">{APP_TITLE} failed to start</h2><p>The desktop wrapper could not boot the local service.</p><pre style=\"white-space: pre-wrap; background: #f4f4f4; padding: 16px; border-radius: 12px;\">{details}</pre><p>Rebuild the app bundle and make sure the helper executable is included.</p></body></html>"\n\ndef main():\n    try:\n        backend = Backend()\n        atexit.register(backend.stop)\n        backend.start()\n    except Exception as exc:\n        webview.create_window(APP_TITLE, html=error_html(exc), width=760, height=420)\n        webview.start(gui="cocoa", debug=False)\n        return 1\n    window = webview.create_window(APP_TITLE, backend.url, width=1360, height=900, min_size=(980, 720))\n    window.events.closed += backend.stop\n    try:\n        webview.start(gui="cocoa", debug=not getattr(sys, "frozen", False))\n    finally:\n        backend.stop()\n    return 0\n\nraise SystemExit(main())')
